 32→fn position_near_top(window: &tauri::WebviewWindow) {
 33→    let monitor = window
 34→        .current_monitor()
 35→        .ok()
 36→        .flatten()
 37→        .or_else(|| window.primary_monitor().ok().flatten());
 38→
 39→    if let Some(monitor) = monitor {
 40→        let monitor_size = monitor.size();
 41→        let monitor_pos = monitor.position();
 42→
 43→        if let Ok(window_size) = window.outer_size() {
 44→            let x = monitor_pos.x + (monitor_size.width as i32 - window_size.width as i32) / 2;
 45→            let y = monitor_pos.y + (monitor_size.height as i32) / 5;
 46→
 47→            if let Err(e) = window.set_position(tauri::PhysicalPosition::new(x, y)) {
 48→                eprintln!("failed to position window: {e}");
 49→            }
 50→        }
 51→    } else if let Err(e) = window.center() {
 52→        eprintln!("failed to center window: {e}");
 53→    }
 54→}
