 56→fn show_and_focus(window: &tauri::WebviewWindow) {
 57→    let position_pref = window
 58→        .app_handle()
 59→        .try_state::<Mutex<WindowConfig>>()
 60→        .and_then(|state| state.lock().ok().map(|s| s.position_pref.clone()))
 61→        .unwrap_or_else(|| "top-third".to_string());
 62→
 63→    if position_pref == "center" {
 64→        if let Err(e) = window.center() {
 65→            eprintln!("failed to center window: {e}");
 66→        }
 67→    } else {
 68→        position_near_top(window);
 69→    }
 70→
 71→    if let Err(e) = window.show() {
 72→        eprintln!("failed to show window: {e}");
 73→    }
 74→    if let Err(e) = window.set_focus() {
 75→        eprintln!("failed to focus window: {e}");
 76→    }
 77→}
