439→fn extract_png_from_icns(icns_data: &[u8]) -> Option<Vec<u8>> {
440→    if icns_data.len() < 8 || &icns_data[0..4] != b"icns" {
441→        return None;
442→    }
443→
444→    let total_len = u32::from_be_bytes(icns_data[4..8].try_into().ok()?) as usize;
445→    let total_len = total_len.min(icns_data.len());
446→
447→    let preferred: &[&[u8; 4]] = &[
448→        b"icp5", b"icp6", b"icp4", b"ic07",
449→    ];
450→
451→    let mut offset = 8;
452→    let mut entries: Vec<(&[u8], &[u8])> = Vec::new();
453→
454→    while offset + 8 <= total_len {
455→        let type_code = &icns_data[offset..offset + 4];
456→        let entry_len = u32::from_be_bytes(icns_data[offset + 4..offset + 8].try_into().ok()?) as usize;
457→        if entry_len < 8 || offset + entry_len > total_len {
458→            break;
459→        }
460→        let data = &icns_data[offset + 8..offset + entry_len];
461→        entries.push((type_code, data));
462→        offset += entry_len;
463→    }
464→
465→    for pref in preferred {
466→        for (type_code, data) in &entries {
467→            if *type_code == pref.as_slice() && data.starts_with(&[0x89, 0x50, 0x4E, 0x47]) {
468→                return Some(data.to_vec());
469→            }
470→        }
471→    }
472→
473→    let max_fallback_size = 200_000;
474→    for (_, data) in &entries {
475→        if data.starts_with(&[0x89, 0x50, 0x4E, 0x47]) && data.len() <= max_fallback_size {
476→            return Some(data.to_vec());
477→        }
478→    }
479→
480→    None
481→}
482→
483→fn extract_app_icon(app_path: &std::path::Path, dict: &plist::Dictionary) -> Option<String> {
484→    let icon_name = dict
485→        .get("CFBundleIconFile")
486→        .and_then(|v| v.as_string())
487→        .unwrap_or("AppIcon");
488→
489→    let icon_filename = if icon_name.ends_with(".icns") {
490→        icon_name.to_string()
491→    } else {
492→        format!("{icon_name}.icns")
493→    };
494→
495→    let icns_path = app_path.join("Contents/Resources").join(&icon_filename);
496→    let icns_data = std::fs::read(&icns_path).ok()?;
497→    let png_data = extract_png_from_icns(&icns_data)?;
498→
499→    Some(format!(
500→        "data:image/png;base64,{}",
501→        base64::engine::general_purpose::STANDARD.encode(&png_data)
502→    ))
503→}
504→
505→fn build_app_list() -> Vec<AppEntry> {
506→    let mut apps = Vec::new();
507→    let mut seen_paths = std::collections::HashSet::new();
508→
509→    let mut dirs = vec![std::path::PathBuf::from("/Applications")];
510→    if let Some(home) = dirs_next::home_dir() {
511→        dirs.push(home.join("Applications"));
512→    }
513→
514→    for dir in &dirs {
515→        for app_path in scan_app_dir(dir, 1) {
516→            let path_str = app_path.to_string_lossy().to_string();
517→            if !seen_paths.insert(path_str.clone()) {
518→                continue;
519→            }
520→
521→            let file_stem = app_path
522→                .file_stem()
523→                .map(|s| s.to_string_lossy().to_string())
524→                .unwrap_or_default();
525→
526→            let plist_dict = read_info_plist(&app_path);
527→            let name = plist_dict
528→                .as_ref()
529→                .and_then(display_name_from_plist)
530→                .unwrap_or_else(|| file_stem.clone());
531→            let icon = plist_dict
532→                .as_ref()
533→                .and_then(|dict| extract_app_icon(&app_path, dict));
534→
535→            let id = format!("app-{:x}", {
536→                use std::hash::{Hash, Hasher};
537→                let mut h = std::collections::hash_map::DefaultHasher::new();
538→                path_str.hash(&mut h);
539→                h.finish()
540→            });
541→
542→            apps.push(AppEntry {
543→                id,
544→                name,
545→                path: path_str,
546→                icon,
547→            });
548→        }
549→    }
550→
551→    apps.sort_by(|a, b| a.name.to_lowercase().cmp(&b.name.to_lowercase()));
552→    apps
553→}
