754→                    INSERT INTO quicklinks_fts(rowid, name, link) VALUES (NEW.rowid, NEW.name, NEW.link);
755→                END;
756→                CREATE TRIGGER IF NOT EXISTS quicklinks_ad AFTER DELETE ON quicklinks BEGIN
757→                    INSERT INTO quicklinks_fts(quicklinks_fts, rowid, name, link) VALUES ('delete', OLD.rowid, OLD.name, OLD.link);
758→                END;
759→                CREATE TRIGGER IF NOT EXISTS quicklinks_au AFTER UPDATE ON quicklinks BEGIN
760→                    INSERT INTO quicklinks_fts(quicklinks_fts, rowid, name, link) VALUES ('delete', OLD.rowid, OLD.name, OLD.link);
761→                    INSERT INTO quicklinks_fts(rowid, name, link) VALUES (NEW.rowid, NEW.name, NEW.link);
762→                END;
763→
764→                CREATE INDEX IF NOT EXISTS idx_clipboard_copied_at ON clipboard_entries(copied_at);
765→                CREATE INDEX IF NOT EXISTS idx_clipboard_pinned ON clipboard_entries(pinned);
766→                CREATE INDEX IF NOT EXISTS idx_recent_commands_used_at ON recent_commands(used_at);
767→                CREATE UNIQUE INDEX IF NOT EXISTS idx_snippets_keyword ON snippets(keyword) WHERE keyword != '';
768→            ",
769→            kind: MigrationKind::Up,
770→        },
771→    ]
772→}
773→
774→#[cfg_attr(mobile, tauri::mobile_entry_point)]
775→pub fn run() {
776→    tauri::Builder::default()
777→        .plugin(tauri_plugin_clipboard_manager::init())
778→        .plugin(tauri_plugin_shell::init())
779→        .plugin(
780→            tauri_plugin_sql::Builder::default()
781→                .add_migrations("sqlite:raycast_clone.db", db_migrations())
782→                .build(),
783→        )
784→        .manage(Mutex::new(WindowConfig::default()))
785→        .manage(Mutex::new(AppCache::default()))
786→        .invoke_handler(tauri::generate_handler![
787→            set_window_position_pref,
788→            search_files,
789→            open_file,
790→            reveal_in_finder,
791→            move_to_trash,
792→            discover_applications,
793→            launch_application
794→        ])
795→        .setup(|app| {
796→            #[cfg(desktop)]
797→            {
798→                let shortcut = Shortcut::new(Some(Modifiers::ALT), Code::Space);
799→                let window = app
800→                    .get_webview_window("main")
801→                    .expect("main window not found");
802→
803→                let window_for_blur = window.clone();
804→                window.on_window_event(move |event| {
