useEffect(() => {
  let cancelled = false;
  Promise.all([
    settingsDb.get(SETTINGS_DB_KEY),
    settingsDb.get(EXTENSIONS_DB_KEY),
  ])
    .then(([rawSettings, rawExtensions]) => {
      if (cancelled) return;
      const stored = parseSettings(rawSettings);
      if (stored) {
        setSettings(prev => ({
          ...prev,
          ...stored,
          appearance: prev.appearance,
        }));
      }
      const states = parseExtensionStates(rawExtensions);
      if (states) {
        setExtensions(
          MOCK_EXTENSIONS.map(ext => ({
            ...ext,
            enabled: states[ext.id] ?? ext.enabled,
          })),
        );
      }
    })
    .catch(console.error);
  return () => {
    cancelled = true;
  };
}, []);

useEffect(() => {
  setSettings(prev => ({
    ...prev,
    appearance: themePreference,
  }));
}, [themePreference]);

const handleSettingsChange = useCallback(
  (newSettings: GeneralSettings) => {
    setSettings(newSettings);
    settingsDb
      .set(SETTINGS_DB_KEY, JSON.stringify(newSettings))
      .catch(console.error);
    if (
      newSettings.appearance === 'dark' ||
      newSettings.appearance === 'light' ||
      newSettings.appearance === 'system'
    ) {
      setTheme(newSettings.appearance);
    }
  },
  [setTheme],
);

const handleQueryChange = useCallback((value: string) => {
  setQuery(value);
}, []);

const handleTabChange = useCallback((value: string) => {
  if (isSettingsTab(value)) {
    setActiveTab(value);
    setQuery('');
  }
}, []);

const handleToggleExtension = useCallback((id: string) => {
  setExtensions(prev => {
    const next = prev.map(ext =>
      ext.id === id
        ? {
            ...ext,
            enabled: !ext.enabled,
          }
        : ext);
    const states: Record<string, boolean> = {};
    for (const ext of next) {
      states[ext.id] = ext.enabled;
    }
    settingsDb
      .set(EXTENSIONS_DB_KEY, JSON.stringify(states))
      .catch(console.error);
    return next;
  });
}, []);

const handleExport = useCallback(() => {
  showHUD({
    icon: <CopyHUDIcon />,
    title: 'Settings Exported',
  });
}, [showHUD]);

const handleImport = useCallback(() => {
  showHUD({
    icon: <CopyHUDIcon />,
    title: 'Settings Imported',
  });
}, [showHUD]);

