            <RefreshIconSmall />
          </div>
          <span className="settings-action-row__label">Clear Cache</span>
          <span className="settings-action-row__hint">Free up space</span>
        </div>
        <div
          className="settings-action-row settings-action-row--destructive"
          onClick={onResetAll}
          role="button"
          tabIndex={0}
          onKeyDown={e => {
            if (e.key === 'Enter' || e.key === ' ') {
              e.preventDefault();
